const MAX_MESSAGE_LENGTH = 4000;


return $input.all().map(item => {

  // Extract message from the current item in the batch
  const message = item.json.message || {};

  // Safely extract and limit text
  const text =
    typeof message.text === "string"
      ? message.text.trim().slice(0, MAX_MESSAGE_LENGTH)
      : null;

  // Return the mapped JSON object
  return {
    json: {
      chat_id: message.chat?.id ?? null,
      text,
      message_id: message.message_id ?? null,
      sender_name: message.from?.first_name ?? null,
      username: message.from?.username ?? null,
      language: message.from?.language_code ?? null,
      hasText: Boolean(text), // accurately flags if text is present and not just empty spaces
      isStatusUpdate: false
    }
  };
});

// 1. Safely get the meta data for the CURRENT user in the batch.
// We use a try/catch fallback to ensure n8n perfectly matches the history to the correct user.
let meta;
try {
  meta = $('Extract Meta Message').item.json;
} catch (e) {
  meta = $('Extract Meta Message').first().json;
}

// 2. Extract and sanitize the rows
const validRows = items
  .map(i => i.json)
  // CRITICAL: Filter out empty rows (happens when a new user has no history)
  .filter(r => r.role && r.content) 
  .reverse();

// 3. Format history, or provide a clean starting state for new users
const last_8_messages = validRows.length > 0 
  ? validRows.map(r => `${r.role.toUpperCase()}: ${r.content}`).join("\n")
  : "System: This is a new conversation. No previous history.";

return [{
  json: {
    ...meta,
    last_8_messages
  }
}];

const items = $input.all(); // Ensure items are explicitly loaded

const validEscalateReasons = [
  "medical_risk",
  "off_topic",
  "no_faq_match"
];

for (const item of items) {
  try {
    // 1. Handle HTTP/Node errors
    if (item.json.error) {
      item.json = {
        status: "error",
        reason: "http_request_failed",
        error: item.json.error.message || String(item.json.error)
      };
      continue;
    }

    // 2. Handle Gemini Safety Filters & Blocks (NEW)
    const candidate = item.json.candidates?.[0];
    const promptFeedback = item.json.promptFeedback;

    if (promptFeedback?.blockReason) {
      throw new Error(`Prompt blocked by Google Safety: ${promptFeedback.blockReason}`);
    }

    if (candidate?.finishReason && candidate.finishReason !== "STOP") {
      throw new Error(`Gemini stopped generating. Reason: ${candidate.finishReason}`);
    }

    // 3. Extract Gemini response
    const text = candidate?.content?.parts?.[0]?.text || "";

    if (!text.trim()) {
       throw new Error("Gemini returned an completely empty text response.");
    }

    const clean = text
      .replace(/```json/g, "")
      .replace(/```/g, "")
      .trim();

    // 4. Token & Cost Calculation
    const usage = item.json.usageMetadata || {};
    const promptTokens = Number(usage.promptTokenCount ?? 0);
    const completionTokens = Number(usage.candidatesTokenCount ?? 0);
    const totalTokens = Number(usage.totalTokenCount ?? 0);
    const model = item.json.modelVersion ?? "gemini-2.5-flash";

    const cost = (promptTokens * 0.30 + completionTokens * 2.50) / 1000000;

    // 5. Safely Parse JSON (NEW)
    let result;
    try {
      result = JSON.parse(clean);
    } catch (parseError) {
      // If parsing fails, attach the RAW text so the admin can debug it!
      throw new Error(`JSON Parse Error: ${parseError.message}. RAW OUTPUT: ${clean.substring(0, 200)}`);
    }

    // ===== ANSWERED =====
    if (result.status === "answered") {
      // Hard stop to prevent Telegram from crashing
      if (typeof result.answer === "string" && result.answer.length > 4000) {
        result.answer = result.answer.substring(0, 3990) + "... [Message truncated]";
      }

      if (typeof result.answer !== "string" || result.answer.trim() === "") {
        throw new Error("Missing or invalid answer field in answered status");
      }

      if (typeof result.language_detected !== "string" || result.language_detected.trim() === "") {
        throw new Error("Missing or invalid language_detected field in answered status");
      }

      if (result.reason) throw new Error("Forbidden field: reason in answered status");
      if (result.message) throw new Error("Forbidden field: message in answered status");

      item.json = {
        status: "answered",
        answer: result.answer,
        reason: null,
        language_detected: result.language_detected.charAt(0).toUpperCase() + result.language_detected.slice(1).toLowerCase(),
        model,
        prompt_tokens: promptTokens,
        completion_tokens: completionTokens,
        total_tokens: totalTokens,
        cost_usd: Number(cost.toFixed(6))
      };
    }

    // ===== ESCALATE =====
    else if (result.status === "escalate") {
      if (!result.reason) throw new Error("Missing reason field in escalate status");
      if (!validEscalateReasons.includes(result.reason)) throw new Error(`Invalid escalate reason: ${result.reason}`);
      if (typeof result.message !== "string" || result.message.trim() === "") {
        throw new Error("Missing or invalid message field in escalate status");
      }
      if (typeof result.language_detected !== "string" || result.language_detected.trim() === "") {
        throw new Error("Missing or invalid language_detected field in escalate status");
      }
      if (result.answer) throw new Error("Forbidden field: answer in escalate");

      item.json = {
        status: "escalate",
        reason: result.reason,
        message: result.message,
        language_detected: result.language_detected.charAt(0).toUpperCase() + result.language_detected.slice(1).toLowerCase(),
        model,
        prompt_tokens: promptTokens,
        completion_tokens: completionTokens,
        total_tokens: totalTokens,
        cost_usd: Number(cost.toFixed(6))
      };
    }

    // ===== Invalid Status =====
    else {
      throw new Error(`Unknown status from AI: ${result.status}`);
    }

  } catch (e) {
    item.json = {
      status: "error",
      reason: "ai_validation_failed",
      error: e.message
    };
  }
}

return items;

