// 1. Safely get the Airtable output
const items = $input.all();

// Safely handle both raw API responses and standard n8n Airtable responses
const records = items[0]?.json?.records || items.map(i => i.json);

// 2. Format the FAQ Sheet
const faq_sheet_content = records
  .map(r => {
    const fields = r.fields || {};
    const q = fields.question || '';
    const a = fields.answer || '';

    // Only return if both exist (cleaner than checking for strings later)
    if (q && a) {
      return `س: ${q}\nج: ${a}`;
    }
    return null;
  })
  .filter(item => item !== null)
  .join('\n\n');

// 3. SECURE THE USER DATA
// Because Airtable wiped the user data from the stream, we MUST pull it 
// back from your first node. (Make sure this matches the exact name of your first node!)
let userData = {};
try {
  // Try to grab the exact user data that triggered this specific execution
  userData = $('Extract Meta Message').item.json;
} catch (e) {
  // Fallback if item matching fails
  userData = $('Extract Meta Message').first().json;
}

return [{
  json: {
    ...userData, // Restores chat_id, text, etc.
    faq_sheet_content // Adds your perfectly formatted FAQ
  }
}];

